issues.body:
### Steps to reproduce

1. Place a `WidgetSpan` in a `SelectionArea`.
2. Select some text.
3. Call `setState(() {})`. Notice that the context menu disappears and that the selection starts flickering.

This behavior only exists if there is a `WidgetSpan` in the `Text.rich`. Removing the `WidgetSpan` resolves the issue.

This behavior is even more of an issue if we remove the `await Future.delayed(Duration(seconds: 1))` in the listener. Since we call `setState((){})` the same frame that the selection is created, you don't even see a text-selection visually when you attempt to create one.

### Expected results

Calling `setState()` should not cause the context menu to disappear or the selection to flicker/disappear.

### Actual results

Calling `setState()` when a `WidgetSpan` is in a `Text.rich` causes the context menu to disappear and the selection to flicker/disappear.

### Code sample

<details open><summary>Code sample</summary>

```dart
import 'dart:async';

import 'package:flutter/material.dart';

Future<void> main() async {
  runApp(MaterialApp(home: SelectionApp()));
}

class SelectionApp extends StatefulWidget {
  const SelectionApp({super.key});

  @override
  State<SelectionApp> createState() => _SelectionAppState();
}

class _SelectionAppState extends State<SelectionApp> {
  late SelectionListenerNotifier selectionListenerNotifierDelayed;
  late SelectionListenerNotifier selectionListenerNotifierInstant;

  @override
  void initState() {
    super.initState();
    selectionListenerNotifierDelayed = SelectionListenerNotifier();
    selectionListenerNotifierDelayed.addListener(() async {
      await Future.delayed(Duration(seconds: 1));
      setState(() {});
    });

    selectionListenerNotifierInstant = SelectionListenerNotifier();
    selectionListenerNotifierInstant.addListener(() => setState(() {}));
  }

  @override
  void dispose() {
    super.dispose();
    selectionListenerNotifierDelayed.dispose();
    selectionListenerNotifierInstant.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      body: Padding(
        padding: EdgeInsets.all(32),
        child: Column(
          spacing: 32,
          children: [
            SelectionArea(
              child: SelectionListener(
                selectionNotifier: selectionListenerNotifierDelayed,
                child: Text.rich(
                  TextSpan(
                    text: 'setState will be called 1 second after a selection.',
                    style: TextStyle(fontSize: 32),
                    children: [WidgetSpan(child: FlutterLogo(size: 24))],
                  ),
                ),
              ),
            ),
            SelectionArea(
              child: SelectionListener(
                selectionNotifier: selectionListenerNotifierInstant,
                child: Text.rich(
                  TextSpan(
                    text: 'setState will be called right after a selection.',
                    style: TextStyle(fontSize: 32),
                    children: [WidgetSpan(child: FlutterLogo(size: 24))],
                  ),
                ),
              ),
            ),
          ],
        ),
      ),
    );
  }
}
```

