import 'package:flutter/material.dart';

Future<void> main() async {
  runApp(MaterialApp(home: SelectionApp()));
}

class SelectionApp extends StatefulWidget {
  const SelectionApp({super.key});

  @override
  State<SelectionApp> createState() => _SelectionAppState();
}

class _SelectionAppState extends State<SelectionApp> {
  @override
  Widget build(BuildContext context) {
    return Scaffold(
      body: Padding(
        padding: EdgeInsets.all(32),

        child: Column(
          spacing: 32,

          children: [
            SelectableText.rich(
              TextSpan(
                text: 'setState will be called 1 second after a selection.',

                style: TextStyle(fontSize: 32),

                children: const [WidgetSpan(child: FlutterLogo(size: 24))],
              ),

              onSelectionChanged: (selection, cause) async {
                await Future.delayed(Duration(seconds: 1));

                setState(() {});
              },
            ),

            SelectableText.rich(
              TextSpan(
                text: 'setState will be called right after a selection.',

                style: TextStyle(fontSize: 32),

                children: const [WidgetSpan(child: FlutterLogo(size: 24))],
              ),

              onSelectionChanged: (selection, cause) {
                setState(() {});
              },
            ),
          ],
        ),
      ),
    );
  }
}
